class Solution {
public:
    long long countGoodIntegers(int n, int k) {
        long long total = 0;
        int max_sum = 9 * n;
        vector<long long> fact(11);
        fact[0] = 1;
        for (int i = 1; i <= 10; ++i) fact[i] = fact[i - 1] * i;

        auto multinom = [&](const vector<int>& cnt) -> long long {
            long long denom = 1;
            for (int c : cnt) denom *= fact[c];
            return fact[n] / denom;
        };

        auto is_possible = [&](const vector<int>& cnt) -> bool {
            int sum = 0;
            for (int d = 0; d < 10; ++d) sum += d * cnt[d];
            if (sum % k != 0) return false;
            vector<int> odd;
            for (int d = 0; d < 10; ++d) if (cnt[d] & 1) odd.push_back(d);
            return odd.size() <= (n & 1);
        };

        vector<int> cnt(10);
        function<void(int, int)> dfs = [&](int pos, int rem) {
            if (pos == 9) {
                cnt[9] = rem;
                if (cnt[0] == n) return;
                if (is_possible(cnt)) {
                    long long ways = multinom(cnt);
                    if (cnt[0] > 0) {
                        vector<int> tmp = cnt;
                        tmp[0]--;
                        ways -= multinom(tmp);
                    }
                    total += ways;
                }
                return;
            }
            for (int take = 0; take <= rem; ++take) {
                cnt[pos] = take;
                dfs(pos + 1, rem - take);
            }
        };
        dfs(0, n);
        return total;
    }
};
```
efficiency: HIGH
time complexity: O(P(n) * 10) where P(n) is the number of integer partitions of n into 10 parts (bounded by C(n+9,9) ≤ 92k for n≤10)
space complexity: O(1) auxiliary (recursion depth ≤10)
energy implications: LOW
explanation: Enumerate every possible digit-frequency multiset (partition of n into 10 digits). For each multiset check if it can form a palindrome (≤1 odd count) and if the digit sum is divisible by k. Count permutations avoiding leading zeros via inclusion-exclusion.

